"use strict";var SYK={conductor:{$animations:[],playing_animations:[],update:function(){SYK.conductor.updateScrollVariables();SYK.conductor.checkForNewItems()},updateScrollVariables:function(){SYK.conductor.scrollTop=$(window).scrollTop();SYK.conductor.scrollBottom=SYK.conductor.scrollTop+$(window).height()},checkForNewItems:function(){SYK.conductor.$animations.each(function(){var e=$(this);if(SYK.conductor.shouldPlayItem(e)){SYK.conductor.playing_animations.push(e.attr("id"));SYK.conductor.playItem(e)}})},shouldPlayItem:function(e){return SYK.conductor.itemInViewport(e)&&SYK.conductor.itemNotPlayedYet(e)},itemInViewport:function(e){return e.offset().top<SYK.conductor.scrollBottom},itemNotPlayedYet:function(e){return $.inArray(e.attr("id"),SYK.conductor.playing_animations)==-1},playItem:function(e){var t=e.parent().parent().find(".adScroller");SYK.disclaimerBox.startScroll(t);SYK.imageAnimator.loopImage(e)}},imageAnimator:{loopCount:1,frame1Length:5e3,frame2Length:1e4,frame3Length:5e3,loopLength:function(){return SYK.imageAnimator.frame1Length+SYK.imageAnimator.frame2Length+SYK.imageAnimator.frame3Length},loopImage:function(e){for(var t=1;t<=SYK.imageAnimator.loopCount;t++){window.setTimeout(function(){SYK.imageAnimator.rotate(e,"frame2")},SYK.imageAnimator.frame1Length+SYK.imageAnimator.loopLength()*(t-1));window.setTimeout(function(){SYK.imageAnimator.rotate(e,"frame3")},SYK.imageAnimator.frame1Length+SYK.imageAnimator.frame2Length+SYK.imageAnimator.loopLength()*(t-1));if(t<SYK.imageAnimator.loopCount){window.setTimeout(function(){SYK.imageAnimator.rotate(e,"frame1")},SYK.imageAnimator.loopLength()+SYK.imageAnimator.loopLength()*(t-1))}}},rotate:function(e,t){e.removeClass("frame1 frame2 frame3");e.addClass(t)}},disclaimerBox:{startScroll:function(e){var t=setInterval(function(){var t=e.scrollTop();e.scrollTop(t+2)},e.data("speed"));e.mouseover(function(){clearInterval(t)})}}};$(function(){SYK.conductor.$animations=$(".sykbanner_image");SYK.conductor.update();$(window).scroll(function(){SYK.conductor.update()});$(window).load(function(){SYK.conductor.update()})})